// ─── HELPERS ───
export function getWordle(): string[] {
  const seen = new Set<string>()
  return PLAYERS_DB
    .map(p => p.surname)
    .filter(s => {
      if (s.length < 4 || s.length > 11) return false
      if (seen.has(s)) return false
      seen.add(s)
      return true
    })
}

export function getActivePlayersSuitable() {
  return PLAYERS_DB.filter(p => p.imageUrl && p.hints && p.hints.length >= 3)
}
